import{_ as t,a,b as r,c as o}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as l,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Ajouter un canal Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/google-drive.md","filePath":"fr-FR/upload/google-drive.md","lastUpdated":1781962217000}'),s={name:"fr-FR/upload/google-drive.md"};function c(p,e,h,u,g,m){return l(),n("div",null,[...e[0]||(e[0]=[d('<h1 id="ajouter-un-canal-google-drive" tabindex="-1">Ajouter un canal Google Drive <a class="header-anchor" href="#ajouter-un-canal-google-drive" aria-label="Permalink to &quot;Ajouter un canal Google Drive&quot;">​</a></h1><p>Le canal Google Drive utilise un compte Google Drive comme destination de stockage.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Google</td><td>Gérer Drive et OAuth</td></tr><tr><td>Projet Google Cloud</td><td>Créer l’OAuth Client</td></tr><tr><td>Client ID / Client Secret</td><td>Autoriser ImgBed</td></tr><tr><td>Refresh Token</td><td>Maintenir l’accès dans le temps</td></tr><tr><td>Domaine ImgBed</td><td>Configurer le callback OAuth</td></tr></tbody></table><h2 id="creer-l-oauth-client" tabindex="-1">Créer l’OAuth Client <a class="header-anchor" href="#creer-l-oauth-client" aria-label="Permalink to &quot;Créer l’OAuth Client&quot;">​</a></h2><p>Dans Google Cloud Console, créez un OAuth Client de type Web application.</p><p><img src="'+t+'" alt="Créer l’OAuth Client" loading="lazy"></p><p>Ajoutez cette URI comme redirection autorisée :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Configurer l’URL OAuth" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>Google Drive</code> et renseignez Client ID et Client Secret.</p><p><img src="'+r+'" alt="Configuration Google Drive" loading="lazy"></p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>Google Drive Main</code></td></tr><tr><td>Client ID</td><td>OAuth Client ID</td></tr><tr><td>Client Secret</td><td>OAuth Client Secret</td></tr><tr><td>Refresh Token</td><td>À obtenir ensuite</td></tr><tr><td>Dossier racine</td><td>Optionnel, souvent <code>imgbed</code></td></tr></tbody></table><h2 id="obtenir-le-refresh-token" tabindex="-1">Obtenir le Refresh Token <a class="header-anchor" href="#obtenir-le-refresh-token" aria-label="Permalink to &quot;Obtenir le Refresh Token&quot;">​</a></h2><ol><li>Dans ImgBed, cliquez sur <code>Obtenir le token</code>.</li><li>Connectez-vous avec le compte Google qui servira de destination.</li><li>Acceptez les permissions.</li><li>Copiez le Refresh Token affiché sur la page de callback.</li><li>Collez-le dans le champ <code>Refresh Token</code>.</li></ol><p><img src="'+o+'" alt="Copier le Refresh Token" loading="lazy"></p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><ol><li>Enregistrez le canal.</li><li>Envoyez une image de test.</li><li>Vérifiez qu’elle apparaît dans Google Drive.</li><li>Ouvrez le lien renvoyé par ImgBed.</li></ol><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Si l’écran de consentement OAuth n’est pas prêt, l’autorisation peut échouer.</li><li>Le compte qui génère le Refresh Token sera le compte de stockage.</li><li>Si Drive n’a plus d’espace, l’upload échouera.</li><li>Ne publiez pas le Client Secret.</li></ul>',21)])])}const C=i(s,[["render",c]]);export{v as __pageData,C as default};
